    {"act":"Anti-Terrorism Act 1997","short":"ATA","sec":"7","title":"Punishment for Terrorism","text":"Whoever commits an act of terrorism shall be punished with imprisonment of either description for a term which shall not be less than three years and may extend to imprisonment for life or with death.","category":"Criminal","sub":"Terrorism","keywords":["terrorism punishment","ATA 7","terrorist","bomb blast","armed attack"],"punishment":"3 years to death","bailable":False,"severity":"High"},

