    {"act":"Companies Act 2017","short":"Companies Act","sec":"167","title":"Accounts and Audit","text":"Every company shall keep proper books of account and shall prepare and file annual audited accounts with the registrar within 30 days of the annual general meeting.","category":"Corporate","sub":"Accounts","keywords":["company accounts","audit","annual accounts","SECP filing","Companies Act 167","books of account","audit report"],"punishment":"Fine and imprisonment for directors","bailable":True,"severity":"Medium"},

    {"act":"Companies Act 2017","short":"Companies Act","sec":"204","title":"Liability of Directors","text":"A director shall not act on behalf of the company to promote his own interests. A director who acts in good faith, in the best interests of the company, and with proper care and diligence will not be liable for losses.","category":"Corporate","sub":"Directors","keywords":["director liability","company director","breach of duty","Companies Act 204","director responsibility","corporate governance"],"punishment":"Fine or imprisonment","bailable":True,"severity":"Medium"},

