    {"act":"Income Tax Ordinance 2001","short":"ITO","sec":"114","title":"Filing of Tax Return","text":"Every person whose taxable income in a tax year exceeds the maximum amount not chargeable to tax shall furnish a return of income for that year. Salaried persons, companies, associations of persons, and business owners are required to file annual returns.","category":"Tax","sub":"Income Tax","keywords":["income tax","tax return","filing","ITO","FBR","taxable income","return daakhil","tax jama","NTN"],"punishment":"Penalty + default surcharge","bailable":None,"severity":"Medium"},

    {"act":"Income Tax Ordinance 2001","short":"ITO","sec":"182","title":"Penalty for Non-Filing","text":"Any person who fails to furnish a return of income within the due date shall pay a penalty equal to 0.1% of the tax payable per day of default, subject to a minimum penalty of five thousand rupees.","category":"Tax","sub":"Income Tax","keywords":["tax penalty","late filing","ITO 182","FBR fine","non-filing penalty","return late"],"punishment":"0.1% per day + minimum Rs.5000","bailable":None,"severity":"Medium"},

