    {"act":"Control of Narcotic Substances Act 1997","short":"CNSA","sec":"9","title":"Punishment for Drug Offences","text":"Whoever is found in possession of, or produces, processes, sells, purchases, transports, delivers, stores, exhibits, imports into or exports from Pakistan narcotic drugs or psychotropic substances shall be punished. Small quantity: 2 years. Large quantity: death or life imprisonment.","category":"Criminal","sub":"Narcotics","keywords":["drugs","narcotics","CNSA","charas","heroin","cocaine","drug possession","drug trafficking","nashe","manshiyat"],"punishment":"2 years to death depending on quantity","bailable":False,"severity":"High"},

