    {"act":"Competition Act 2010","short":"Competition","sec":"3","title":"Prohibited Agreements","text":"No undertaking or association of undertakings shall enter into any agreement or engage in any practice which has or is likely to have the effect of preventing, restricting or reducing competition.","category":"Consumer","sub":"Competition","keywords":["competition","monopoly","cartel","price fixing","Competition Act","SECP","market abuse","anti-competitive"],"punishment":"Fine up to 10% of annual turnover","bailable":None,"severity":"Medium"},

    {"act":"Punjab Consumer Protection Act 2005","short":"CPA Punjab","sec":"4","title":"Consumer Rights","text":"A consumer shall have the right to be protected against marketing of goods and services which are hazardous to life and property; to be informed about the quality, quantity, potency, purity, standard and price; and to seek redressal against unfair trade practices.","category":"Consumer","sub":"Consumer Rights","keywords":["consumer rights","Punjab CPA","defective goods","misleading","complaint","consumer court","kharab maal","saman wapis","refund"],"punishment":"Compensation + fine","bailable":None,"severity":"Medium"},
